const payload = $json.body ?? $json;
const findings = [];
if (!payload.record_url && (!payload.screenshots || payload.screenshots.length === 0)) {
  findings.push({ type: 'missing_evidence', severity: 'warning', message: '缺少可核验链接或截图，需要补充材料。' });
}
if (Number(payload.claimed_amount ?? 0) <= 0) {
  findings.push({ type: 'amount_missing', severity: 'info', message: '未提供有效金额，暂不做金额一致性判断。' });
}
const needsReview = findings.length > 0;
return [{ json: { skill_id: 'fan.record_verify.v1', status: 'ok', verification_status: needsReview ? 'needs_review' : 'verified', confidence: needsReview ? 0.45 : 0.72, findings, recommended_action: needsReview ? '请进入人工复核或要求用户补充材料。' : '可进入下一步审核流程。', received: payload } }];
